//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
  //필수입력항목 체크
  if (!(await $c.gus.cfValidate($p, [tb_Conditon]))) {
    return;
  }
  if (!(await $c.gus.cfValidate($p, [ica_rsltsYmFrom]))) {
    return;
  }
  dma_viewCond.set("lobranCd", ed_lobranCd.getValue());
  dma_viewCond.set("bilgClntNo", ed_bilgClntNo.getValue());
  dma_viewCond.set("rsltsYmFrom", ica_rsltsYmFrom.getValue());
  dma_viewCond.set("transCargoClsCd", acb_transCargoClsCd.getValue());
  $c.sbm.execute($p, sbm_retrieve);
};

//-------------------------------------------------------------------------
// 그리드 decode
//-------------------------------------------------------------------------
scwin.displayFm = function (data) {
  return $c.gus.decode($p, data, "120", "운송", "110", "하역", "140", "부산복운", "130", "보관", "");
};
scwin.displayFm2 = function (data) {
  return $c.gus.decode($p, data, "B", "BULK", "C", "CNTR", "");
};

//-------------------------------------------------------------------------
// 조회 완료시
//-------------------------------------------------------------------------
scwin.sbm_retrieve_submitDone = function (e) {
  let totalRow = ds_SellingContents.getTotalRow();
  spa_totalRows.setValue(totalRow);
  if (totalRow == 0) {
    $c.win.alert($p, "조회된 데이터가 없습니다.");
  } else {
    scwin.f_gridView();
  }
};

//-------------------------------------------------------------------------
// 그리드 데이터 수정
//-------------------------------------------------------------------------
scwin.f_gridView = function () {
  for (i = 0; i <= ds_SellingContents.getTotalRow(); i++) {
    if (ds_SellingContents.getCellData(i, "clntClsCd").substring(0, 2) == "01") {
      ds_SellingContents.setCellData(i, "clntClsCd", "선사");
    } else if (ds_SellingContents.getCellData(i, "clntClsCd") == "02LI") {
      ds_SellingContents.setCellData(i, "clntClsCd", "화주당사");
    } else if (ds_SellingContents.getCellData(i, "clntClsCd") == "02LS") {
      ds_SellingContents.setCellData(i, "clntClsCd", "화주자가");
    } else if (ds_SellingContents.getCellData(i, "clntClsCd") == "ALL") {
      ds_SellingContents.setCellData(i, "clntClsCd", "");
    }
    if (ds_SellingContents.getCellData(i, "bizDomCd") == "120") {
      ds_SellingContents.setCellData(i, "wrkGbnCd", "");
    }
  }
};

//-------------------------------------------------------------------------
// Cell 더블클릭 이벤트
//-------------------------------------------------------------------------
scwin.gr_SellingContents_onDblClick = function (rowIndex, columnIndex, columnId) {
  if (columnIndex < 7) {
    return;
  }
  scwin.f_bilgClntNoSellingContents(rowIndex, columnId);
};

//-------------------------------------------------------------------------
// 청구처별 실적현황 조회 
//-------------------------------------------------------------------------
scwin.f_bilgClntNoSellingContents = function (row, colid) {
  let condition = "";
  let strOrderDetailUrl = "";
  let menuTitle = "";
  let v_flag = Window.name;
  let v_colIdMmdd = colid.substring(colid.length - 2, colid.length);
  let v_rsltsYyMm = ica_rsltsYmFrom.getValue();
  let v_colId = colid;
  let v_rsltsYyMmdd = v_rsltsYyMm + v_colIdMmdd;
  let v_rlstsYyMmFirst = v_rsltsYyMmdd;
  let v_rlstsYyMmLast = v_rsltsYyMmdd;
  let v_transCargoClsCd = ds_SellingContents.getCellData(row, "transCargoClsCd");
  let v_bizDomCd = ds_SellingContents.getCellData(row, "bizDomCd");
  let v_wrkGbn = ds_SellingContents.getCellData(row, "wrkGbn");
  let v_lineCd = ds_SellingContents.getCellData(row, "lineCd");

  // console.log("colid?? " + gr_SellingContents.getColumnIndex(colid));
  // console.log("v_colIdMmdd?? " + v_colIdMmdd);
  // console.log("v_rsltsYyMmdd?? " + v_rsltsYyMmdd);

  if (gr_SellingContents.getColumnIndex(colid) == "7" || gr_SellingContents.getColumnIndex(colid) == "8") {
    v_rlstsYyMmFirst = ica_rsltsYmFrom.getValue().substring(0, 6) + "01";
    v_rlstsYyMmLast = ica_rsltsYmFrom.getValue().substring(0, 6) + $c.date.getLastDateOfMonth($p, ica_rsltsYmFrom.getValue().substring(0, 6));
  }

  // console.log("v_rlstsYyMmFirst?" + v_rlstsYyMmFirst);
  // console.log("v_rlstsYyMmLast?" + v_rlstsYyMmLast);

  // 보관이면서 작업구분이 CK나 CL일때는 벌크로 넘긴다 
  if (v_bizDomCd == "130" && v_wrkGbn == "CL") {
    v_transCargoClsCd = "B";
  } else if (v_bizDomCd == "120") {
    v_transCargoClsCd = "";
  }
  dma_selldecunsetaggr_con.set("bilgLodeptCd", ed_lobranCd.getValue());
  dma_selldecunsetaggr_con.set("qryConDtFm", v_rlstsYyMmFirst);
  dma_selldecunsetaggr_con.set("qryConDtTo", v_rlstsYyMmLast);
  dma_selldecunsetaggr_con.set("bilgClntNo", ds_SellingContents.getCellData(row, "bilgClntNo"));
  dma_selldecunsetaggr_con.set("transCargoClsCd", v_transCargoClsCd);
  dma_selldecunsetaggr_con.set("lineCd", v_lineCd);

  // 현재 frame창의 이름을 넘겨준다.
  condition = {
    bizDom: v_flag,
    qryConDtFm: v_rlstsYyMmFirst,
    qryConDtTo: v_rlstsYyMmLast,
    bilgLodeptCd: ed_lobranCd.getValue(),
    transCargoClsCd: v_transCargoClsCd,
    lineCd: v_lineCd,
    bilgClntNo: ds_SellingContents.getCellData(row, "bilgClntNo"),
    strlobranCd: ed_lobranCd.getValue(),
    strlobranNm: ed_lobranNm.getValue(),
    qryConDt: v_rlstsYyMmFirst.substring(0, 6),
    qryConLastDt: v_rlstsYyMmLast
    // , selPchLodeptCd : ed_lobranCd.getValue()
    ,
    ds_selldecunsetaggr_con: dma_selldecunsetaggr_con.getJSON()
  };
  console.log("넘어갈떄 flag ? " + v_flag);
  strOrderDetailUrl = "/ui/ds/fs/bilg/fs_204_02_04b.xml"; //통합매출 확정/미확정 조회
  menuTitle = "통합매출 확정/미확정 조회";

  //cfTabMenuUpdate( strOrderDetailUrl+condition , menuTitle);  	

  $c.win.openMenu($p, menuTitle, strOrderDetailUrl, "fs_204_02_04b.jsp", condition);
};

